			</scroll-view>
			<view class="composer"><textarea v-model="input" auto-height maxlength="1000" placeholder="输入你的问题，AI 会尽力为你解答…" @confirm="send"/><button :disabled="sending" @click="send">➤</button></view>
		</view>
	</view></AppShell>
</template>
<script>
import AppShell from '../../components/AppShell.vue';import{agentApi}from'../../api'
export default{components:{AppShell},data(){return{sessionId:null,input:'',messages:[],sending:false,scrollTarget:'',suggestions:['幼猫每天应该吃几顿？','狗狗突然不爱喝水怎么办？','如何帮助宠物适应新环境？']}},methods:{reset(){this.sessionId=null;this.messages=[]},ask(text){this.input=text;this.send()},async send(){const content=this.input.trim();if(!content||this.sending)return;if(!uni.getStorageSync('access_token'))return uni.navigateTo({url:'/pages/auth/login'});this.input='';this.messages.push({role:'user',content});this.sending=true;this.scroll();try{if(!this.sessionId){const session=await agentApi.createSession();this.sessionId=session.id}const res=await agentApi.send(this.sessionId,content);this.messages.push(res.assistant_message)}catch(e){this.messages.push({role:'assistant',content:`暂时无法回答：${e.message}`})}finally{this.sending=false;this.scroll()}},scroll(){this.$nextTick(()=>{this.scrollTarget=`msg-${this.messages.length-1}`})}}}
</script>
