x;font-weight:800}.welcome-sub{max-width:500px;margin-top:10px;color:var(--color-text-secondary);font-size:13px;line-height:1.7}.suggestions{display:flex;flex-wrap:wrap;justify-content:center;gap:9px;margin-top:20px}.suggestions view{padding:9px 15px;border:1px solid var(--color-border);border-radius:18px;background:#fff;font-size:11px}.message-row{display:flex;max-width:780px;gap:10px;margin:20px auto}.message-row.user{flex-direction:row-reverse}.message-avatar{display:flex;width:34px;height:34px;flex:none;align-items:center;justify-content:center;border-radius:11px;background:#fff0e4;color:var(--color-primary);font-size:11px;font-weight:800}.bubble{max-width:75%;padding:13px 16px;border-radius:5px 16px 16px 16px;background:#f8f3ee;font-size:13px;line-height:1.8}.user .bubble{border-radius:16px 5px 16px 16px;background:var(--color-primary);color:#fff}.risk{margin-top:11px;padding:10px;border-radius:8px;background:#fff0e7;color:#c5662a;font-size:10px;line-height:1.5}.typing{color:var(--color-text-secondary)}.composer{display:flex;flex:none;align-items:flex-end;gap:10px;margin:16px 5% 24px;padding:10px 10px 10px 17px;border:1px solid var(--color-border);border-radius:18px;background:#fff;box-shadow:0 8px 30px rgba(70,45,24,.08)}.composer textarea{flex:1;min-height:26px;max-height:100px;padding:5px 0;font-size:13px}.composer button{display:flex;width:38px;height:38px;align-items:center;justify-content:center;margin:0;border-radius:12px;background:var(--color-primary);color:#fff;font-size:15px;line-height:38px}
